realtime.code:
// Escuchar cambios en asignaciones de un proyecto (requiere SDK)
const channel = timeboxing
  .channel('project-allocations')
  .on(
    'postgres_changes',
    {
      event: '*',           // INSERT, UPDATE, DELETE (o uno concreto)
      schema: 'public',
      table: 'allocations',
      filter: `project_id=eq.${projectId}`
    },
    (payload) => {
      console.log('Cambio detectado:', payload.eventType, payload.new)
      // payload.new = fila tras el cambio
      // payload.old = fila antes del cambio (solo en UPDATE/DELETE)
    }
  )
  .subscribe()

// Cancelar suscripción cuando no haga falta
timeboxing.removeChannel(channel)

