import { createClient } from '@supabase/supabase-js'

const timeboxing = createClient(
  'https://api.taimbox.com',
  process.env.SUPABASE_ANON_KEY!,
  {
    global: {
      headers: { Authorization: `Bearer ${process.env.TIMEBOXING_API_TOKEN}` }
    }
  }
)

const { data, error } = await timeboxing
  .from('employees')
  .select('id, name, role')
  .eq('is_active', true)
  .limit(5)

if (error) {
  console.error('Error de conexión:', error.message)
} else {
  console.log('¡Conexión correcta! Empleados:', data)
  // [{ id: "...", name: "Ana García", role: "Diseñador" }, ...]
}

